SELECT COUNT(DISTINCT S.PK_SIAPE) FROM SERVIDOR S WHERE LOWER(COALESCE(S.CONTRATO,'')) = 'efetivos' AND LOWER(COALESCE(S.SIGLA_CAMPUS,'')) = 'ana' AND LOWER(COALESCE(S.AREA_INGRESSO,'')) LIKE '%letras%' AND (S.DATA_INGRESSO_IFG IS NULL OR S.DATA_INGRESSO_IFG <= '2024-06-30') AND S.SAIU_DO_IFG = FALSE